// Coffee mug — replicad/BREP showcase: cylinder + shell op for the cavity,
// torus arc for the handle, coffee filling the cavity.
const { BREP } = api;

// Body: 50 mm dia, 70 mm tall, walls 2.5 mm, open top.
// Outer rim at z=70, inner floor at z=2.5, inner radius 22.5.
const outerBody = BREP.cylinder(25, 70);
const hollowBody = BREP.shell(outerBody, -2.5, { topZ: true });

// Handle: torus (major 14, minor 3.5), rotated to lie on its side, and
// translated so its centre sits just outside the mug wall. The inner half
// of the donut overlaps the cylindrical body and gets absorbed by the
// union; the outer half is the graspable handle. Centred vertically at
// z=35 so it sits mid-mug.
const handle = BREP.torus(14, 3.5)
  .rotate(90, [0, 1, 0])
  .translate([25, 0, 35]);

// Coffee: fills the cavity from the floor up to z=55 (below the 70 mm rim).
// Radius 23 so it bites 0.5 mm into the 22.5 mm inner wall along its whole
// height, and the base starts at z=2 so it overlaps the 2.5 mm floor. That
// solid, continuous overlap fuses the coffee into the mug as ONE printable
// solid (a thin disc with only a 0.5 mm annular touch stays disconnected).
const coffee = BREP.cylinder(23, 53).translate([0, 0, 2]);

return BREP.fuseAll([hollowBody, handle, coffee]);

